import { z } from 'zod';
import { getSectionUrl } from '../../utils/url-helpers.js';
/**
 * Raw section fields (the persisted shape). Exposed so schemas that extend
 * or override a field — notably the webhook variant — can reuse the base
 * without duplicating every field.
 */
export const SectionBaseSchema = z.object({
    id: z.string(),
    userId: z.string(),
    projectId: z.string(),
    addedAt: z.coerce.date(),
    updatedAt: z.coerce.date(),
    archivedAt: z.coerce.date().nullable(),
    name: z.string(),
    description: z.string().nullable(),
    sectionOrder: z.number().int(),
    isArchived: z.boolean(),
    isDeleted: z.boolean(),
    isCollapsed: z.boolean(),
});
export const SectionSchema = SectionBaseSchema.transform((data) => (Object.assign(Object.assign({}, data), { url: getSectionUrl(data.id, data.name) })));
